#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const LL Mod = 1e9+7;
struct Mat{LL n,m,p[10][10];}B,Ans;LL n,Sum;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
Mat operator * (const Mat &X , const Mat &Y){
    Mat Z;Z.n=X.n,Z.m=Y.m;
    for(int i=0;i<=Z.n;i++)
        for(int j=0;j<=Z.m;j++)Z.p[i][j]=0;
    for(int i=0;i<=Z.n;i++)for(int j=0;j<=Z.m;j++)
        for(int k=0;k<=X.m;k++)Z.p[i][j]=(Z.p[i][j]+X.p[i][k]*Y.p[k][j])%Mod;
    return Z;
}
Mat QP(Mat A,Mat X,LL Y){while(Y){if(Y&1)A=A*X;X=X*X,Y>>=1;}return A;}
int main(){
    n=read(),Ans.n=0,Ans.m=9;
    if(n==1){cout<<"10\n";return 0;}
    for(int i=1;i<=9;i++)Ans.p[0][i]=1;
    B.n=9,B.m=9;
    for(int i=0;i<=9;i++)
        for(int j=max(0,i-2);j<=min(9,i+2);j++)B.p[j][i]=1;
    Ans=QP(Ans,B,n-1);
    for(int i=0;i<=9;i++)Sum=(Sum+Ans.p[0][i])%Mod;
    cout<<Sum<<"\n";
    return 0;
}
